  `mother_occupation` varchar(50) DEFAULT NULL,
  `mother_contact` varchar(15) DEFAULT NULL,
  `guardian_name` varchar(100) DEFAULT NULL,
  `guardian_relation` varchar(50) DEFAULT NULL,
  `guardian_contact` varchar(15) DEFAULT NULL,
